class Solution:
    def findKthNumber(self, n: int, k: int) -> int:
        cur = 1
        k -= 1
        while k > 0:
            step = self._count_steps(n, cur, cur + 1)
            if k >= step:
                k -= step
                cur += 1
            else:
                k -= 1
                cur *= 10
        return cur

    def _count_steps(self, n, n1, n2):
        steps = 0
        while n1 <= n:
            steps += min(n + 1, n2) - n1
            n1 *= 10
            n2 *= 10
        return steps
